def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    ranges = []
    start = nums[0]
    end = nums[0]

    for num in nums[1:]:
        if num == end + 1:
            end = num
        else:
            if start != end:
                ranges.append(f'{start}-{end}')
            else:
                ranges.append(str(start))
            start = num
            end = num

    if start != end:
        ranges.append(f'{start}-{end}')
    else:
        ranges.append(str(start))

    return ','.join(ranges)
